// // This module implements a 2-to-1 multiplexer that selects between two 32-bit inputs based on a 2-bit select signal. When sel is 00, the output y mirrors input a; when sel is 01, y selects input b; and when sel is 10, y mirrors input a again.
module top_module(a,b,sel,y);input [31:0] a,b;
input [1:0] sel;

output reg [31:0] y;

always@(a,b,sel)
begin
    if(sel == 2'b00)
        y = a;
    else if(sel == 2'b01)
        y = b;
    else if(sel == 2'b10)
        y = a;

end


endmodule
